SELECT users.*
FROM users
INNER JOIN (
    SELECT created_by FROM budget_proposals GROUP BY created_by
) bp ON users.user_id = bp.created_by
LEFT JOIN (
    SELECT created_by FROM expenditures GROUP BY created_by
) e ON users.user_id = e.created_by
WHERE e.created_by IS NULL;

SELECT ministry_name
FROM ministries
WHERE ministry_id = 1;

SELECT COUNT(*)
FROM budget_proposals
WHERE ministry_id = 1 AND fiscal_year_id = 1;

SELECT users.user_id, users.user_name, ministries.ministry_name
FROM users
INNER JOIN ministries ON users.ministry_id = ministries.ministry_id;

SELECT ministries.ministry_name, ministries.head_of_ministry, ministries.address, budgets.total
FROM ministries
JOIN budgets ON ministries.ministry_id = budgets.ministry_id;
